module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const md = (t) => (t && String(t).trim() !== '') ? ('\n\n' + t + '\n\n') : '';
// Fall back to identity if an older app build doesn't pass resolve().
const R = (typeof resolve === 'function') ? resolve : (p) => p;
const image = (args.image || '').trim();
const name = (args.name || '').trim();
const role = (args.role || '').trim();
let size = parseFloat(args.size); if (!Number.isFinite(size) || size <= 0) size = 96;
let border = parseFloat(args.border); if (!Number.isFinite(border) || border < 0) border = 3;
const bordercolor = (args.bordercolor && String(args.bordercolor).trim()) || 'var(--accent-color)';
const alignKey = String(args.align || 'center').toLowerCase();
const margin = alignKey === 'left' ? '1rem auto 1rem 0' : alignKey === 'right' ? '1rem 0 1rem auto' : '1rem auto';

const ring = 'width:' + size + 'px; height:' + size + 'px; border:' + border + 'px solid ' + bordercolor + ';';
const avatar = image
  ? '<img class="mdp-av-img" src="' + esc(R(image)) + '" alt="' + esc(name) + '" style="' + ring + '"/>'
  : '<div class="mdp-av-initial" style="' + ring + ' color:' + bordercolor + '; font-size:' + Math.round(size * 0.42) + 'px;">' + (name ? esc(name.charAt(0).toUpperCase()) : '?') + '</div>';

return '\n\n<div class="mdp-mod-avatar" style="margin:' + margin + ';">' +
  avatar +
  (name ? '<div class="mdp-av-name">' + md(name) + '</div>' : '') +
  (role ? '<div class="mdp-av-role">' + md(role) + '</div>' : '') +
  '</div>\n\n';
